182	        int n = ast_new();
183	        node_type[n] = NODE_QLED;
184	        left = n;
185	        parse_pos++;
186	    } else if (ty == TOK_QSW) {
187	        int n = ast_new();
188	        node_type[n] = NODE_QSW;
189	        left = n;
190	        parse_pos++;
191	    } else if (ty == TOK_IDENT) {
192	        int sym_idx = sym_lookup(parse_line, tok_val[parse_pos]);
193	        if (sym_idx < 0) { parse_err = 1; return 0; }
194	        parse_pos++;
195	        if (tok_type[parse_pos] == TOK_LBRAK) {
196	            // IDENT[expr] -- shared variable indexed read
197	            parse_pos++;
198	            int idx_expr = parse_node(0);
199	            if (parse_err) return 0;
200	            if (tok_type[parse_pos] != TOK_RBRAK) { parse_err = 1; return 0; }
201	            parse_pos++;
202	            int nd = ast_new();
203	            node_type[nd] = NODE_SVO_READ;
204	            node_val[nd] = sym_idx;
205	            node_right[nd] = idx_expr;
206	            left = nd;
207	        } else {
208	            left = ast_ident(sym_idx);
209	        }
210	    } else if (is_binop(ty) && tok_type[parse_pos + 1] == TOK_SLASH) {
211	        // Reduce operator: +/ -/ */ (op followed by slash)
212	        int op = ty;
213	        parse_pos = parse_pos + 2;
214	        int operand = parse_node(0);
215	        if (parse_err) return 0;
216	        left = ast_reduce(op, operand);
217	    } else if (ty == TOK_RES) {
218	        // Monadic primitive function (e.g. iota expr)
219	        int res_id = tok_val[parse_pos];
220	        parse_pos++;
221	        int operand = parse_node(0);
222	        if (parse_err) return 0;
223	        left = ast_monad(res_id, operand);
