269	// Parse the token stream. Returns root node index, or -1 on error.
270	// line is needed for identifier name resolution into the symbol table.
271	int parse(char *line) {
272	    node_count = 0;
273	    parse_pos = 0;
274	    parse_err = 0;
275	    parse_line = line;
276	
277	    // Check for qled assignment: qled <- expr
278	    if (tok_type[0] == TOK_QLED && tok_type[1] == TOK_ASSIGN) {
279	        parse_pos = 2;
280	        int expr = parse_node(0);
281	        if (parse_err) return -1;
282	        if (tok_type[parse_pos] != TOK_EOL) return -1;
283	        int n = ast_new();
284	        node_type[n] = NODE_QLED_ASSIGN;
285	        node_right[n] = expr;
286	        return n;
287	    }
288	
289	    // Check for qsw assignment: qsw is read-only, reject with SYNTAX ERROR
290	    if (tok_type[0] == TOK_QSW && tok_type[1] == TOK_ASSIGN) {
291	        return -1;
292	    }
293	
294	    // Check for quad output: [] <- expr (IBM 5100 convention)
295	    if (tok_type[0] == TOK_QUAD && tok_type[1] == TOK_ASSIGN) {
296	        parse_pos = 2;
297	        int expr = parse_node(0);
298	        if (parse_err) return -1;
299	        if (tok_type[parse_pos] != TOK_EOL) return -1;
300	        int n = ast_new();
301	        node_type[n] = NODE_QOUT;
302	        node_right[n] = expr;
303	        return n;
304	    }
305	
306	    // Check for shared variable indexed write: IDENT[expr] <- expr
307	    if (tok_type[0] == TOK_IDENT && tok_type[1] == TOK_LBRAK) {
308	        int sym_idx = sym_lookup(line, tok_val[0]);
309	        if (sym_idx < 0) { return -1; }
310	        parse_pos = 2;
311	        int idx_expr = parse_node(0);
312	        if (parse_err) return -1;
313	        if (tok_type[parse_pos] != TOK_RBRAK) { parse_err = 1; return -1; }
314	        parse_pos++;
315	        if (tok_type[parse_pos] == TOK_ASSIGN) {
316	            // IDENT[expr] <- expr (indexed write)
317	            parse_pos++;
318	            int val_expr = parse_node(0);
319	            if (parse_err) return -1;
320	            if (tok_type[parse_pos] != TOK_EOL) return -1;
321	            int n = ast_new();
322	            node_type[n] = NODE_SVO_WRITE;
323	            node_val[n] = sym_idx;
324	            node_left[n] = idx_expr;
325	            node_right[n] = val_expr;
326	            return n;
327	        }
328	        if (tok_type[parse_pos] != TOK_EOL) {
329	            // IDENT[expr] followed by more (could be in expression context)
330	            // For now, only standalone read supported at top level
331	            // Fall through to expression parsing below
332	            parse_pos = 0;
333	            node_count = 0;
334	            parse_err = 0;
335	        } else {
336	            // IDENT[expr] standalone read
337	            int n = ast_new();
338	            node_type[n] = NODE_SVO_READ;
339	            node_val[n] = sym_idx;
340	            node_right[n] = idx_expr;
341	            return n;
342	        }
343	    }
344	
345	    // Check for goto: goto expr  or  goto (expr)/LABEL
346	    if (tok_type[0] == TOK_GOTO) {
347	        parse_pos = 1;
348	        if (tok_type[1] == TOK_LPAREN) {
349	            // Conditional: goto (expr)/TARGET
350	            parse_pos = 2;
351	            int cond = parse_node(0);
352	            if (parse_err) return -1;
353	            if (tok_type[parse_pos] != TOK_RPAREN) return -1;
354	            parse_pos++;
355	            if (tok_type[parse_pos] != TOK_SLASH) return -1;
356	            parse_pos++;
357	            int target = parse_node(0);
358	            if (parse_err) return -1;
359	            if (tok_type[parse_pos] != TOK_EOL) return -1;
360	            int n = ast_new();
361	            node_type[n] = NODE_CGOTO;
362	            node_left[n] = cond;
363	            node_right[n] = target;
364	            return n;
365	        }
366	        // Unconditional: goto expr
367	        int target = parse_node(0);
368	        if (parse_err) return -1;
369	        if (tok_type[parse_pos] != TOK_EOL) return -1;
370	        int n = ast_new();
371	        node_type[n] = NODE_GOTO;
372	        node_right[n] = target;
373	        return n;
374	    }
375	
376	    // Check for assignment: IDENT <- expr
377	    if (tok_type[0] == TOK_IDENT && tok_type[1] == TOK_ASSIGN) {
378	        int sym_idx = sym_lookup(line, tok_val[0]);
379	        if (sym_idx < 0) { return -1; }
380	        parse_pos = 2;
381	        int expr = parse_node(0);
382	        if (parse_err) return -1;
383	        if (tok_type[parse_pos] != TOK_EOL) return -1;
384	        return ast_assign(sym_idx, expr);
385	    }
386	
387	    int root = parse_node(0);
388	
389	    if (!parse_err && tok_type[parse_pos] != TOK_EOL) {
390	        parse_err = 1;
391	    }
392	
393	    if (parse_err) return -1;
394	    return root;
395	}
