397	// Debug: dump AST with full parenthesization
398	void ast_dump(int n) {
399	    if (n < 0 || n >= node_count) return;
400	
401	    int ty = node_type[n];
402	    if (ty == NODE_NUM) {
403	        print_int(node_val[n]);
404	    } else if (ty == NODE_BINOP) {
405	        putchar(40);
406	        ast_dump(node_left[n]);
407	        putchar(32);
408	        if (node_val[n] == TOK_PLUS)  putchar(43);
409	        if (node_val[n] == TOK_MINUS) putchar(45);
410	        if (node_val[n] == TOK_STAR)  putchar(42);
411	        if (node_val[n] == TOK_SLASH) putchar(47);
412	        putchar(32);
413	        ast_dump(node_right[n]);
414	        putchar(41);
415	    } else if (ty == NODE_NEG) {
416	        putchar(40);
417	        putchar(45);
418	        ast_dump(node_right[n]);
419	        putchar(41);
420	    }
421	}
