1	// COR24 APL Interpreter -- Evaluator
2	// Tree-walking evaluator returning array heap indices.
3	// Every result is an array (scalars wrapped via arr_scalar).
4	// Supports element-wise ops on vectors with scalar extension.
5	
6	#pragma once
7	
8	// Error codes: 0=none, 1=DOMAIN, 2=VALUE, 3=LENGTH, 4=RANK, 5=WS FULL
9	int eval_err;
10	
11	// Branch target: -1=no branch, 0=exit, >0=line number (1-based)
12	int branch_target;
13	
14	// Shadow register for LED D2 (0xFF0000 is write-only for LEDs)
15	// Stores the user-visible value (1=on, 0=off), not the raw active-low bit
16	int qled_shadow;
17	
18	// Apply a binary op to two scalars
19	int eval_binop_scalar(int op, int a, int b) {
20	    if (op == TOK_PLUS)       return a + b;
21	    if (op == TOK_MINUS)      return a - b;
22	    if (op == TOK_STAR)       return a * b;
23	    if (op == TOK_SLASH) {
24	        if (b == 0) { eval_err = 1; return 0; }
25	        return a / b;
26	    }
27	    eval_err = 1;
28	    return 0;
29	}
30	
31	// Evaluate AST node, return heap index of result array.
32	// On error, sets eval_err and returns -1.
33	int eval(int n) {
34	    if (eval_err) return -1;
35	    if (n < 0 || n >= node_count) {
36	        eval_err = 1;
37	        return -1;
38	    }
39	
40	    int ty = node_type[n];
41	
42	    if (ty == NODE_NUM) {
43	        int r = arr_scalar(node_val[n]);
44	        if (r < 0) { eval_err = 5; return -1; }
45	        return r;
46	    }
47	
48	    if (ty == NODE_VEC) {
49	        return node_val[n];
50	    }
51	
52	    if (ty == NODE_IDENT) {
53	        int idx = node_val[n];
54	        if (!sym_set_flag[idx]) {
55	            eval_err = 2;
56	            return -1;
57	        }
58	        return sym_val[idx];
59	    }
60	
61	    if (ty == NODE_ASSIGN) {
62	        int idx = node_val[n];
63	        int v = eval(node_right[n]);
64	        if (eval_err) return -1;
65	        sym_val[idx] = v;
66	        sym_set_flag[idx] = 1;
67	        return v;
68	    }
69	
70	    if (ty == NODE_QOUT) {
71	        int v = eval(node_right[n]);
72	        if (eval_err) return -1;
73	        return v;
74	    }
75	
76	    if (ty == NODE_QLED) {
77	        // Read LED D2 from shadow register (1=on, 0=off)
78	        int r = arr_scalar(qled_shadow);
79	        if (r < 0) { eval_err = 5; return -1; }
80	        return r;
81	    }
82	
83	    if (ty == NODE_QSW) {
84	        // Read switch S2: bit 0 of 0xFF0000, inverted (1=pressed, 0=released)
85	        int raw = *(char *)0xFF0000;
86	        int val = (raw ^ 1) & 1;
87	        int r = arr_scalar(val);
88	        if (r < 0) { eval_err = 5; return -1; }
89	        return r;
90	    }
91	
92	    if (ty == NODE_QLED_ASSIGN) {
93	        int v = eval(node_right[n]);
94	        if (eval_err) return -1;
95	        if (arr_rank(v) != 0) { eval_err = 4; return -1; }
96	        int val = arr_get(v, 0) & 1;
97	        qled_shadow = val;
98	        // Write LED D2: invert bit 0 (active-low: 1=on writes 0)
99	        *(char *)0xFF0000 = val ^ 1;
100	        return v;
101	    }
102	
103	    if (ty == NODE_QSVO) {
104	        // Shared variable offer: IDENT qsvo AP
105	        // Evaluate AP number, couple symbol if AP supported
106	        int v = eval(node_right[n]);
107	        if (eval_err) return -1;
108	        if (arr_rank(v) != 0) { eval_err = 4; return -1; }
109	        int ap = arr_get(v, 0);
110	        int sym_idx = node_val[n];
111	        if (ap == 242) {
112	            // AP 242: MMIO byte access (FF0000+offset)
113	            svo_ap[sym_idx] = 242;
114	            int r = arr_scalar(2);
115	            if (r < 0) { eval_err = 5; return -1; }
116	            return r;
117	        }
118	        // Unknown AP: return 0 (not coupled)
119	        svo_ap[sym_idx] = 0;
120	        int r = arr_scalar(0);
121	        if (r < 0) { eval_err = 5; return -1; }
122	        return r;
123	    }
124	
125	    if (ty == NODE_SVO_READ) {
126	        // Indexed read: IDENT[N]
127	        int sym_idx = node_val[n];
128	        int ap = svo_ap[sym_idx];
129	        if (ap != 0) {
130	            // Shared variable MMIO access
131	            int v = eval(node_right[n]);
132	            if (eval_err) return -1;
133	            if (arr_rank(v) != 0) { eval_err = 4; return -1; }
134	            int offset = arr_get(v, 0);
135	            if (ap == 242) {
136	                int addr = 0xFF0000 + offset;
137	                int val = *(char *)addr;
138	                val = val & 0xFF;
139	                int r = arr_scalar(val);
140	                if (r < 0) { eval_err = 5; return -1; }
141	                return r;
142	            }
143	            eval_err = 1;
144	            return -1;
145	        }
146	        // Regular vector bracket indexing: V[N]
147	        if (!sym_set_flag[sym_idx]) { eval_err = 2; return -1; }
148	        int arr = sym_val[sym_idx];
149	        int v = eval(node_right[n]);
150	        if (eval_err) return -1;
151	        if (arr_rank(v) != 0) { eval_err = 4; return -1; }
152	        int idx = arr_get(v, 0);
153	        int sz = arr_size(arr);
154	        if (idx < 0 || idx >= sz) { eval_err = 3; return -1; }  // INDEX ERROR
155	        int val = arr_get(arr, idx);
156	        int r = arr_scalar(val);
157	        if (r < 0) { eval_err = 5; return -1; }
158	        return r;
159	    }
160	
161	    if (ty == NODE_SVO_WRITE) {
162	        // Indexed write: IDENT[N] <- expr
163	        int sym_idx = node_val[n];
164	        int ap = svo_ap[sym_idx];
165	        if (ap != 0) {
166	            // Shared variable MMIO write
167	            int idx = eval(node_left[n]);
168	            if (eval_err) return -1;
169	            if (arr_rank(idx) != 0) { eval_err = 4; return -1; }
170	            int offset = arr_get(idx, 0);
171	            int v = eval(node_right[n]);
172	            if (eval_err) return -1;
173	            if (arr_rank(v) != 0) { eval_err = 4; return -1; }
174	            int val = arr_get(v, 0);
175	            if (ap == 242) {
176	                int addr = 0xFF0000 + offset;
177	                *(char *)addr = val & 0xFF;
178	                return v;
179	            }
180	            eval_err = 1;
181	            return -1;
182	        }
183	        // Regular vector bracket indexed write: V[N] <- expr
184	        if (!sym_set_flag[sym_idx]) { eval_err = 2; return -1; }
185	        int arr = sym_val[sym_idx];
186	        int idxv = eval(node_left[n]);
187	        if (eval_err) return -1;
188	        if (arr_rank(idxv) != 0) { eval_err = 4; return -1; }
189	        int idx = arr_get(idxv, 0);
190	        int v = eval(node_right[n]);
191	        if (eval_err) return -1;
192	        if (arr_rank(v) != 0) { eval_err = 4; return -1; }
193	        int val = arr_get(v, 0);
194	        int sz = arr_size(arr);
195	        if (idx < 0 || idx >= sz) { eval_err = 3; return -1; }  // INDEX ERROR
196	        arr_set(arr, idx, val);
197	        return v;
198	    }
199	
200	    if (ty == NODE_GOTO) {
201	        int v = eval(node_right[n]);
202	        if (eval_err) return -1;
203	        if (arr_rank(v) != 0) { eval_err = 4; return -1; }
204	        branch_target = arr_get(v, 0);
205	        int r = arr_scalar(0);
206	        if (r < 0) { eval_err = 5; return -1; }
207	        return r;
208	    }
209	
210	    if (ty == NODE_CGOTO) {
211	        int cv = eval(node_left[n]);
212	        if (eval_err) return -1;
213	        if (arr_rank(cv) != 0) { eval_err = 4; return -1; }
214	        int cond = arr_get(cv, 0);
215	        if (cond != 0) {
216	            int tv = eval(node_right[n]);
217	            if (eval_err) return -1;
218	            if (arr_rank(tv) != 0) { eval_err = 4; return -1; }
219	            branch_target = arr_get(tv, 0);
220	        }
221	        int r = arr_scalar(0);
222	        if (r < 0) { eval_err = 5; return -1; }
223	        return r;
224	    }
225	
226	    if (ty == NODE_NEG) {
227	        int v = eval(node_right[n]);
228	        if (eval_err) return -1;
229	        int rk = arr_rank(v);
230	        if (rk == 0) {
231	            int r = arr_scalar(0 - arr_get(v, 0));
232	            if (r < 0) { eval_err = 5; return -1; }
233	            return r;
234	        }
235	        // Negate each element of vector
236	        if (rk == 1) {
237	            int sz = arr_size(v);
238	            int r = arr_vector(sz);
239	            if (r < 0) { eval_err = 5; return -1; }
240	            int i = 0;
241	            while (i < sz) {
242	                arr_set(r, i, 0 - arr_get(v, i));
243	                i++;
244	            }
245	            return r;
246	        }
247	        // Negate each element of matrix
248	        if (rk == 2) {
249	            int d0 = arr_dim0(v);
250	            int d1 = arr_dim1(v);
251	            int sz = d0 * d1;
252	            int r = arr_new(2, d0, d1);
253	            if (r < 0) { eval_err = 5; return -1; }
254	            int i = 0;
255	            while (i < sz) {
256	                arr_set(r, i, 0 - arr_get(v, i));
257	                i++;
258	            }
259	            return r;
260	        }
261	        eval_err = 4;
262	        return -1;
263	    }
264	
265	    if (ty == NODE_MONAD) {
266	        int v = eval(node_right[n]);
267	        if (eval_err) return -1;
268	        int res_id = node_val[n];
269	
270	        if (res_id == RES_IOTA) {
271	            // iota N: generate vector 0 1 2 ... N-1
272	            if (arr_rank(v) != 0) { eval_err = 4; return -1; }
273	            int count = arr_get(v, 0);
274	            if (count < 0) { eval_err = 1; return -1; }
275	            int r = arr_vector(count);
276	            if (r < 0) { eval_err = 5; return -1; }
277	            int i = 0;
278	            while (i < count) {
279	                arr_set(r, i, i);
280	                i++;
281	            }
282	            return r;
283	        }
284	
285	        if (res_id == RES_RHO) {
286	            // rho A: return shape of A
287	            int rk = arr_rank(v);
288	            if (rk == 0) {
289	                // Scalar: shape is empty vector
290	                int r = arr_vector(0);
291	                if (r < 0) { eval_err = 5; return -1; }
292	                return r;
293	            }
294	            if (rk == 1) {
295	                // Vector: shape is 1-element vector with length
296	                int r = arr_scalar(arr_dim0(v));
297	                if (r < 0) { eval_err = 5; return -1; }
298	                return r;
299	            }
300	            if (rk == 2) {
301	                // Matrix: shape is 2-element vector (rows cols)
302	                int r = arr_vector(2);
303	                if (r < 0) { eval_err = 5; return -1; }
304	                arr_set(r, 0, arr_dim0(v));
305	                arr_set(r, 1, arr_dim1(v));
306	                return r;
307	            }
308	            eval_err = 4;
309	            return -1;
310	        }
311	
312	        if (res_id == RES_REV) {
313	            // rev A: reverse a vector
314	            int rk = arr_rank(v);
315	            if (rk == 0) {
316	                // Scalar: reverse is identity
317	                return v;
318	            }
319	            if (rk == 1) {
320	                int sz = arr_size(v);
321	                int r = arr_vector(sz);
322	                if (r < 0) { eval_err = 5; return -1; }
323	                int i = 0;
324	                while (i < sz) {
325	                    arr_set(r, i, arr_get(v, sz - 1 - i));
326	                    i++;
327	                }
328	                return r;
329	            }
330	            eval_err = 4;
331	            return -1;
332	        }
333	
334	        if (res_id == RES_CAT) {
335	            // Monadic cat: ravel (flatten to 1D vector)
336	            int rk = arr_rank(v);
337	            if (rk == 0) {
338	                // Scalar -> 1-element vector
339	                int r = arr_vector(1);
340	                if (r < 0) { eval_err = 5; return -1; }
341	                arr_set(r, 0, arr_get(v, 0));
342	                return r;
343	            }
344	            if (rk == 1) {
345	                // Vector: already 1D, return as-is
346	                return v;
347	            }
348	            if (rk == 2) {
349	                // Matrix -> vector of all elements
350	                int sz = arr_size(v);
351	                int r = arr_vector(sz);
352	                if (r < 0) { eval_err = 5; return -1; }
353	                int i = 0;
354	                while (i < sz) {
355	                    arr_set(r, i, arr_get(v, i));
356	                    i++;
357	                }
358	                return r;
359	            }
360	            eval_err = 4;
361	            return -1;
362	        }
363	
364	        if (res_id == RES_NOT) {
365	            // not A: bitwise NOT (complement)
366	            int rk = arr_rank(v);
367	            if (rk == 0) {
368	                int r = arr_scalar(~arr_get(v, 0));
369	                if (r < 0) { eval_err = 5; return -1; }
370	                return r;
371	            }
372	            if (rk == 1) {
373	                int sz = arr_size(v);
374	                int r = arr_vector(sz);
375	                if (r < 0) { eval_err = 5; return -1; }
376	                int i = 0;
377	                while (i < sz) {
378	                    arr_set(r, i, ~arr_get(v, i));
379	                    i++;
380	                }
381	                return r;
382	            }
383	            if (rk == 2) {
384	                int d0 = arr_dim0(v);
385	                int d1 = arr_dim1(v);
386	                int r = arr_new(2, d0, d1);
387	                if (r < 0) { eval_err = 5; return -1; }
388	                int sz = d0 * d1;
389	                int i = 0;
390	                while (i < sz) {
391	                    arr_set(r, i, ~arr_get(v, i));
392	                    i++;
393	                }
394	                return r;
395	            }
396	            eval_err = 4;
397	            return -1;
398	        }
399	
400	        // Unknown monadic function
401	        eval_err = 1;
402	        return -1;
403	    }
404	
405	    if (ty == NODE_REDUCE) {
406	        int v = eval(node_right[n]);
407	        if (eval_err) return -1;
