1	// COR24 APL Interpreter -- Symbol Table
2	// Linear-scan symbol table for variable storage.
3	// Variable names are uppercase (A-Z, alphanumeric).
4	// Names stored in a flat buffer with NUL terminators.
5	
6	#pragma once
7	
8	#define SYM_MAX   64    // max number of variables
9	#define SYM_NAMES 256   // name buffer size
10	
11	// Symbol storage
12	int sym_val[SYM_MAX];       // value for each symbol
13	int sym_set_flag[SYM_MAX];  // 1 if assigned, 0 if undefined
14	int sym_name_off[SYM_MAX];  // offset into sym_name_buf
15	int sym_count;               // number of symbols defined
16	char sym_name_buf[SYM_NAMES]; // flat name storage
17	int sym_name_pos;            // next free position in name buffer
18	
19	// Shared variable table (□SVO coupling)
20	// svo_ap[i] = AP number for symbol i (0 = not shared)
21	int svo_ap[SYM_MAX];
22	
23	// Reset symbol table (clear all variables)
24	void sym_reset() {
25	    int i = 0;
26	    while (i < sym_count) {
27	        sym_set_flag[i] = 0;
28	        svo_ap[i] = 0;
29	        i++;
30	    }
31	    sym_count = 0;
32	    sym_name_pos = 0;
33	}
34	
35	// Compare identifier at line[pos..] with name at sym_name_buf[off..].
36	// Returns 1 if identical, 0 otherwise.
37	int sym_name_eq(char *line, int pos, int off) {
38	    int i = 0;
39	    while (sym_name_buf[off + i]) {
40	        if (line[pos + i] != sym_name_buf[off + i]) return 0;
41	        i++;
42	    }
43	    // Ensure the identifier in line also ends here
44	    if (is_alnum(line[pos + i])) return 0;
45	    return 1;
46	}
47	
48	// Copy identifier from line[pos..] into name buffer at current position.
49	// Returns the offset where the name was stored.
50	int sym_name_copy(char *line, int pos) {
51	    int off = sym_name_pos;
52	    while (is_alnum(line[pos])) {
53	        sym_name_buf[sym_name_pos] = line[pos];
54	        sym_name_pos++;
55	        pos++;
56	    }
57	    sym_name_buf[sym_name_pos] = 0;
58	    sym_name_pos++;
59	    return off;
60	}
61	
62	// Look up or create a symbol for the identifier at line[pos..].
63	// Returns symbol index (0..SYM_MAX-1), or -1 if table full.
64	int sym_lookup(char *line, int pos) {
65	    int i = 0;
66	    while (i < sym_count) {
67	        if (sym_name_eq(line, pos, sym_name_off[i])) return i;
68	        i++;
69	    }
70	    // Not found -- create new entry
71	    if (sym_count >= SYM_MAX) return -1;
72	    if (sym_name_pos >= SYM_NAMES - 16) return -1;
73	    int idx = sym_count;
74	    sym_name_off[idx] = sym_name_copy(line, pos);
75	    sym_val[idx] = 0;
76	    sym_set_flag[idx] = 0;
77	    sym_count++;
78	    return idx;
79	}
