                    } else if (eval_err == 3) {
                        heap_top = heap_save;
                        io_print("  LENGTH ERROR");
                        if (pc >= 0) { io_print(" ["); print_int(pc + 1); putchar(93); pc = -1; }
                        putchar(10);
